/**
 * Seed the utah_statutes table with reference data.
 * Uses INSERT OR REPLACE keyed on citation to update existing and add new entries.
 */
/**
 * Seed statutes into the utah_statutes table (multi-state support).
 * Uses ON CONFLICT(citation) for idempotent upsert.
 */
export function seedStatutes(db: any, statutes: StatuteSeed[]): void {
  try { db.run('SELECT 1'); } catch { /* db check */ }
  // Ensure unique citation index exists
  try {
    const createIdx = 'CREATE UNIQUE INDEX IF NOT EXISTS idx_statutes_citation_unique ON utah_statutes(citation)';
    db.prepare(createIdx).run();
  } catch { /* exists */ }

  const insert = db.prepare(`
    INSERT INTO utah_statutes (state, state_name, title, chapter, section, subsection, citation, short_title, description, definition, offense_level, category, subcategory, citation_fine)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(citation) DO UPDATE SET
      state = excluded.state,
      state_name = excluded.state_name,
      short_title = excluded.short_title,
      description = excluded.description,
      definition = excluded.definition,
      offense_level = excluded.offense_level,
      subcategory = excluded.subcategory,
      citation_fine = excluded.citation_fine
  `);

  const tx = db.transaction(() => {
    for (const s of statutes) {
      insert.run(s.state, s.state_name, s.title, s.chapter, s.section, s.subsection, s.citation, s.short_title, s.description, s.definition ?? null, s.offense_level, s.category, s.subcategory, s.citation_fine ?? null);
    }
  });

  tx();
}

/** Backward-compatible: seeds Utah statutes only */
export function seedUtahStatutes(db: any): void {
  seedStatutes(db, UTAH_STATUTES);
  console.log(`Seeded/updated ${UTAH_STATUTES.length} Utah statute entries.`);
}
